    *   Perform final cleanup.

### Implementation Details: `web/tests/ingestion_loop.spec.ts`

```typescript
import { test, expect } from '@playwright/test';
import { execSync } from 'child_process';

test.describe('Full Ingestion Loop E2E', () => {
  const repoName = 'e2e-test-repo';
  const sampleFile = 'sample.py';
  const bucket = 'handy-curve-491715-e9-code-snapshots';

  test.beforeAll(async () => {
    // Ensure clean state
    execSync(`python scripts/cleanup_e2e.py --repo ${repoName}`);
  });

  test.afterAll(async () => {
    // Cleanup after test
    execSync(`python scripts/cleanup_e2e.py --repo ${repoName}`);
  });

  test('should ingest file and retrieve via chat', async ({ page }) => {
    // 1. Simulate Ingestion: Upload file to GCS
    // In a real CI, this might be a webhook trigger, but here we simulate the trigger 
    // by placing the file in the bucket prefix that the worker monitors.
    const content = 'def hello_world():\n    return "Hello from E2E test"';
    execSync(`python -c "from google.cloud import storage; client = storage.Client(); bucket = client.bucket('${bucket}'); blob = bucket.blob('${repoName}/${sampleFile}'); blob.upload_from_string('''${content}''')"`);

    // Wait for ingestion processing (polling for DB state)
    console.log('Waiting for ingestion...');
    await page.waitForTimeout(10000); // Wait for background worker

    // 2. Verify UI Retrieval
    await page.goto('/');

    const input = page.locator('input[placeholder*="Ask about project"]');
    await input.fill('What does the hello_world function in sample.py return?');
    await page.keyboard.press('Enter');

    // 3. Assert Response
    const assistantMessage = page.locator('.bg-card').last();
    await expect(assistantMessage).toContainText('Hello from E2E test', { timeout: 30000 });
    await expect(assistantMessage).toContainText(sampleFile);
  });
});
```

